// Pola fetch yang baik dan benar
async function ambilDataMahasiswa() {
  try {
    // fetch() → Promise<Response>
    const response = await fetch('https://api.kampus.id/mahasiswa');

    // Cek apakah request berhasil (status 200-299)
    if (!response.ok) {
      throw new Error(`HTTP Error! Status: ${response.status}`);
    }

    // Parse body response sebagai JSON → Promise<Object>
    const data = await response.json();
    return data;

  } catch (error) {
    console.error('Gagal mengambil data:', error.message);
    throw error; // re-throw agar pemanggil juga bisa handle
  }
}

// Fungsi lengkap: fetch + tampilkan ke DOM
async function muatDaftarMahasiswa() {
  const kontainer = document.querySelector('#daftar-mahasiswa');
  const loading = document.querySelector('#loading-indicator');

  try {
    loading.classList.add('tampil'); // tampilkan spinner

    const mahasiswaList = await ambilDataMahasiswa();

    // Kosongkan kontainer dulu
    kontainer.innerHTML = '';

    // Render setiap mahasiswa ke DOM
    mahasiswaList.forEach(mhs => {
      const kartu = document.createElement('article');
      kartu.classList.add('kartu-mahasiswa');
      kartu.innerHTML = `
        <h3>${mhs.nama}</h3>
        <p>NIM: ${mhs.nim} | IPK: ${mhs.ipk}</p>
      `;
      kontainer.appendChild(kartu);
    });

  } catch (error) {
    kontainer.innerHTML = `
      <div class="pesan-error">
        <p>Gagal memuat data. Silakan coba lagi.</p>
        <button onclick="muatDaftarMahasiswa()">Coba Lagi</button>
      </div>
    `;
  } finally {
    loading.classList.remove('tampil'); // sembunyikan spinner
  }
}

// Mengirim data ke server (POST)
async function simpanMahasiswa(dataBaru) {
  const response = await fetch('https://api.kampus.id/mahasiswa', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${localStorage.getItem('token')}`
    },
    body: JSON.stringify(dataBaru)
  });

  if (!response.ok) throw new Error('Gagal menyimpan data');
  return response.json();
}

