// Pola lengkap: simpan keranjang belanja
function ambilKeranjang() {
  return JSON.parse(localStorage.getItem('keranjang')) ?? [];
}

function simpanKeranjang(keranjang) {
  localStorage.setItem('keranjang', JSON.stringify(keranjang));
}

function tambahKeKeranjang(produk) {
  const keranjang = ambilKeranjang();
  const sudahAda = keranjang.find(item => item.id === produk.id);

  if (sudahAda) {
    sudahAda.qty += 1;
  } else {
    keranjang.push({ ...produk, qty: 1 });
  }

  simpanKeranjang(keranjang);
  updateTampilan Keranjang(keranjang);
}

